import{_ as s}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as n,e}from"./app-46c33a7a.js";const p={},t=e(`<p>binary 与 varbinary 类型和char与varchar类型是相似的，只是他们存储的是二进制数据，也就是说他们是包含字节流而不是字符流，他们有二进制字符的集合和顺序，他们的对比，排序是基于字节的数值进行的</p><p>binary与varbinary的最大长度和char与varchar是一样的，只不过他们是定义<strong>字节长度</strong>，而char和varchar对应的是<strong>字符长度</strong>。</p><h4 id="存储和取出时对尾部空格的处理" tabindex="-1"><a class="header-anchor" href="#存储和取出时对尾部空格的处理" aria-hidden="true">#</a> 存储和取出时对尾部空格的处理</h4><ul><li><p>char(N)用来存储非二进制字符串，插入时，对于少于N个字符的会自动在尾部加空格，查询时，尾部的空格就会被丢弃掉</p></li><li><p>vachar(N) 用来存储非二进制字符串，插入时，对于少于N个字符的不填补空格，查询时，尾部的空格不会被丢弃掉</p></li><li><p>binary(N)存储二进制字符串，插入进，少于N个字节的会自动在尾部加0x00，取出时，所有的字节都保留，返回定义长度的字节长度，在比较的时候，所有的字节都是有效的，并且0x00&lt;space (space对应的是0x20)</p></li><li><p>varbinary在插入不会去填补0x00字节，查询的时候也不会丢弃任何字节，在比较的时候，所有的字节都是有效的，并且0x00&lt;space (space对应的是0x20)</p></li></ul><h4 id="大小比较时" tabindex="-1"><a class="header-anchor" href="#大小比较时" aria-hidden="true">#</a> 大小比较时</h4><p>char与varchar的字符比较中，是忽略大小写与最后的空格的，如：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>mysql<span class="token operator">&gt;</span> <span class="token keyword">select</span> <span class="token string">&#39;a&#39;</span><span class="token operator">=</span><span class="token string">&#39;a &#39;</span> , <span class="token string">&#39;a&#39;</span><span class="token operator">=</span><span class="token string">&#39;A&#39;</span> , <span class="token string">&#39;a&#39;</span><span class="token operator">=</span><span class="token string">&#39;A &#39;</span><span class="token punctuation">;</span>

+----------+---------+----------+
<span class="token operator">|</span> <span class="token string">&#39;a&#39;</span><span class="token operator">=</span><span class="token string">&#39;a &#39;</span> <span class="token operator">|</span> <span class="token string">&#39;a&#39;</span><span class="token operator">=</span><span class="token string">&#39;A&#39;</span> <span class="token operator">|</span> <span class="token string">&#39;a&#39;</span><span class="token operator">=</span><span class="token string">&#39;A &#39;</span> <span class="token operator">|</span>
+----------+---------+----------+
<span class="token operator">|</span>        <span class="token number">1</span> <span class="token operator">|</span>       <span class="token number">1</span> <span class="token operator">|</span>        <span class="token number">1</span> <span class="token operator">|</span>
+----------+---------+----------+
<span class="token number">1</span> row <span class="token keyword">in</span> <span class="token builtin class-name">set</span> <span class="token punctuation">(</span><span class="token number">0.00</span> sec<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>而binary及varbinary的字节比较中，所有的信息都不会被忽略，如：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>mysql<span class="token operator">&gt;</span> create table t <span class="token punctuation">(</span>c BINARY<span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">))</span><span class="token punctuation">;</span>
Query OK, <span class="token number">0</span> rows affected <span class="token punctuation">(</span><span class="token number">0.01</span> sec<span class="token punctuation">)</span>

mysql<span class="token operator">&gt;</span> insert into t <span class="token builtin class-name">set</span> c <span class="token operator">=</span> <span class="token string">&#39;a&#39;</span><span class="token punctuation">;</span>
Query OK, <span class="token number">1</span> row affected <span class="token punctuation">(</span><span class="token number">0.01</span> sec<span class="token punctuation">)</span>

mysql<span class="token operator">&gt;</span> <span class="token keyword">select</span> hex<span class="token punctuation">(</span>c<span class="token punctuation">)</span>, c <span class="token operator">=</span> <span class="token string">&#39;a&#39;</span>, c <span class="token operator">=</span> <span class="token string">&#39;a\\0\\0&#39;</span> from t<span class="token punctuation">;</span>
+--------+---------+-------------+
<span class="token operator">|</span> HEX<span class="token punctuation">(</span>c<span class="token punctuation">)</span> <span class="token operator">|</span> c <span class="token operator">=</span> <span class="token string">&#39;a&#39;</span> <span class="token operator">|</span> c <span class="token operator">=</span> <span class="token string">&#39;a\\0\\0&#39;</span> <span class="token operator">|</span>
+--------+---------+-------------+
<span class="token operator">|</span> <span class="token number">610000</span> <span class="token operator">|</span>       <span class="token number">0</span> <span class="token operator">|</span>           <span class="token number">1</span> <span class="token operator">|</span>
+--------+---------+-------------+
<span class="token number">1</span> row <span class="token keyword">in</span> <span class="token builtin class-name">set</span> <span class="token punctuation">(</span><span class="token number">0.08</span> sec<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,9),o=[t];function r(c,l){return a(),n("div",null,o)}const k=s(p,[["render",r],["__file","Mysql中varbinary、binary、char、varchar异同-ac603ae1.html.vue"]]);export{k as default};
